import hashlib
import base64

SECRET = 'my-secret-key'

def generate_token(user_id: int) -> str:
    payload = f'{user_id}:{SECRET}'
    return base64.b64encode(payload.encode()).decode()

def validate_token(token: str) -> int | None:
    try:
        payload = base64.b64decode(token).decode()
        user_id, secret = payload.split(':')
        if secret == SECRET:
            return int(user_id)
    except:
        pass
    return None
